    "id": "com.steadfastinnovation.android.projectpapyrus",
    "name": "Squid: Take Notes, Markup PDFs",
    "publisher": "Steadfast Innovation, LLC",
    "subtitle": "Steadfast Innovation, LLC - 2012-03-27",
