    "image": "https://play-lh.googleusercontent.com/vi4isC-oHwog6TfuCMTWvmlBZAHG97st_aGk2m1zhk6bdRKH4INVtMlstGL0Rt0mqP77lUQugF8btq2b8H_ysg",
    "updatedAt": "2026-03-23",
